import{_ as a,o,c as s,a2 as t}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"FAQ & Resolução de Problemas","description":"","frontmatter":{},"headers":[],"relativePath":"pt/faq.md","filePath":"pt/faq.md"}'),r={name:"pt/faq.md"};function i(n,e,d,c,l,m){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="faq-resolucao-de-problemas" tabindex="-1"><i class="ph ph-question"></i> FAQ &amp; Resolução de Problemas <a class="header-anchor" href="#faq-resolucao-de-problemas" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-question&quot;&gt;&lt;/i&gt; FAQ &amp; Resolução de Problemas&quot;">​</a></h1><p>Esta secção recolhe respostas às perguntas mais frequentes e soluções para problemas típicos encontrados durante a otimização de WebGL.</p><h2 id="instalacao-e-cena-de-demonstracao" tabindex="-1"><i class="ph ph-package"></i> Instalação e Cena de Demonstração <a class="header-anchor" href="#instalacao-e-cena-de-demonstracao" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-package&quot;&gt;&lt;/i&gt; Instalação e Cena de Demonstração&quot;">​</a></h2><details class="details custom-block"><summary>P: Eu abri a cena de demonstração, mas todos os materiais e objetos estão cor-de-rosa!</summary><p><strong>R:</strong> O seu projeto usa URP, enquanto a cena de demonstração é configurada por padrão para BiRP. Simplesmente extraia o pacote localizado em <code>WebAdaptivePerformance/Demo/Import Me (URP).unitypackage</code>. Os shaders serão atualizados automaticamente.</p></details><details class="details custom-block"><summary>P: Instalei o plugin, mas visualmente, absolutamente nada muda no jogo.</summary><p><strong>R:</strong> Analise a seguinte checklist:</p><ul><li>O plugin está ativado em Project Settings? Os Scalers estão adicionados e ativos?</li><li>Os gráficos do Unity estão originalmente configurados no máximo? O plugin não tem nada a reduzir se as configurações já forem baixas.</li><li>Talvez o dispositivo lide perfeitamente com a carga, e o FPS seja estável. Adicione o prefab <code>Dashboard</code> à cena para observar as decisões em andamento do Indexer.</li><li>Se tudo estiver configurado corretamente mas não há efeito — contacte-nos e nós iremos ajudar com a resolução de problemas.</li></ul></details><h2 id="resolucao-e-interface-ui" tabindex="-1"><i class="ph ph-monitor-play"></i> Resolução e Interface (UI) <a class="header-anchor" href="#resolucao-e-interface-ui" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-monitor-play&quot;&gt;&lt;/i&gt; Resolução e Interface (UI)&quot;">​</a></h2><details class="details custom-block"><summary>P: A resolução não está a mudar (Resolution Scaler inativo).</summary><p><strong>R:</strong> As duas razões mais vulgares:</p><ol><li>Se está a usar <strong>BiRP</strong> e o modo <code>RenderTextureScaling</code>: analise o array <code>Target Tags</code> nas configurações do Scaler. Se a câmara do seu jogo tiver um nome diferente (não <code>MainCamera</code>), precisa inserir a tag respetiva. Caso contrário, o plugin não conseguirá localizá-la.</li><li>O modo <code>NativeBrowserScaling</code> apenas opera numa build WebGL renderizada final. Ele não faz nada no Unity Editor.</li></ol></details><details class="details custom-block"><summary>P: Quando os FPS descem, a minha UI também fica distorcida/turva!</summary><p><strong>R:</strong> Confirme se em BiRP, tem o <code>RenderTextureScaling</code> selecionado. O próprio Canvas necessita de ser definido em modo <code>Screen Space - Overlay</code> (ou use uma câmara dedicada só para a UI).</p></details><details class="details custom-block"><summary>P: Botões UI normais funcionam bem, mas os meus cliques do rato (customizados) em objetos 3D estão errados.</summary><p><strong>R:</strong> Os eventos padrão de EventSystem são perfeitamente reparados pelo nosso componente <code>WebScaledPhysicsRaycaster</code>. Porém, se estiver a chamar raycasts manuais por código (<code>Camera.ScreenPointToRay()</code>), eles falharão a posição do clique porque a resolução da tela não corresponde à renderizada. Para este efeito aplique o método do nosso plugin: <code>WebRaycasterUtility.TryComputeScaledRay()</code>.</p></details><h2 id="metricas-e-comportamento-do-sistema" tabindex="-1"><i class="ph ph-chart-line-up"></i> Métricas e Comportamento do Sistema <a class="header-anchor" href="#metricas-e-comportamento-do-sistema" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-line-up&quot;&gt;&lt;/i&gt; Métricas e Comportamento do Sistema&quot;">​</a></h2><details class="details custom-block"><summary>P: A qualidade gráfica diminuiu por causa de atrasos. Atualmente, os FPS estão altos novamente, mas os gráficos não estão a recuperar!</summary><p><strong>R:</strong> É bastante provável que o <strong>Anti Yo-Yo Penalty System</strong> tenha sido ativado. O plugin bloqueou temporalmente melhorias visuais a fim de impedir instabilidade (Quality flickering).</p><ul><li>Se deseja que os gráficos se estabilizem com mais celeridade, reduza o limite do parâmetro <code>Penalty Lockout Duration</code> (ex., passe para 10 segundos).</li><li>Reveja também o <code>Increase Cooldown</code> — poderá possuir tempos de espera altos demais.</li></ul></details><details class="details custom-block"><summary>P: O Dashboard insiste num Gargalo de CPU (CPU Bottleneck) ou Unknown de forma continuada, apesar da cena estar limpa.</summary><p><strong>R:</strong> Não se esqueça de ativar as <code>Frame Timing Stats</code> no Player Settings. Posteriormente verifique de igual forma se o <code>Application.targetFrameRate = -1</code>. Ao retirar os travões ao refrescamento temporal, liberta e isola as métricas contra abrandamentos induzidos pelo <code>setTimeout</code> do navegador.</p></details><details class="details custom-block"><summary>P: A minha personagem (ou os adereços físicos) engasgam-se ou dão soluços com &quot;lags&quot; fortes.</summary><p><strong>R:</strong> Isto resulta colateralmente devido à ativação forçada do <code>Physics Step Scaler</code>. Ele modula a base do <code>Time.fixedDeltaTime</code> por modo a prevenir colapsos na CPU perante sobrecargas drásticas de desempenho. Garanta e assegure transições puramente fluidas ativando de urgência a preferência (mode) de <code>Interpolate</code> residente na aba do componente <code>Rigidbody</code> de qualquer dos personagens da cena.</p></details><details class="details custom-block"><summary>P: Os Shadow Scalers (Sombras) mantêm-se instigados, todavia a performance permanece decrescente e as sombras intactas.</summary><p><strong>R:</strong> Os ditos plugins supervisionam e operam apenas mediante reflexões dinâmicas diretas em tempo corrente (Realtime). Opcionalmente e sempre que uma configuração de &quot;iluminação no mapa se apresente pré-calculada (Baked/Lightmaps)&quot; esta permanecerá insensível.</p></details><h2 id="scalers-customizados" tabindex="-1"><i class="ph ph-code"></i> Scalers Customizados <a class="header-anchor" href="#scalers-customizados" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-code&quot;&gt;&lt;/i&gt; Scalers Customizados&quot;">​</a></h2><details class="details custom-block"><summary>P: O meu próprio Scaler opera majestosamente no modo Editor, contudo na versão Build WebGL o mesmo pura e simplesmente &quot;esfuma-se&quot;!</summary><p><strong>R:</strong> Sob procedimentos internos normais o integrador de arquitetura IL2CPP aniquilou em escassa conformidade tal vertente por julgar constar código sem finalidade (&quot;dead code&quot;). Proceda na inclusão obrigatória mediante o prefixo de declaração (attribute) <code>[UnityEngine.Scripting.Preserve]</code> adjacente na margem cimeira a encabeçar a classe principal do Custom Scaler que criou.</p></details>',16)])])}const g=a(r,[["render",i]]);export{p as __pageData,g as default};
